@app.route('/messages')
def messages_page():
    # Construct conversations from messages
    messages = read_messages()
    conversations_dict = {}

    for msg in messages:
        # Determine conversation key: between CURRENT_USER and other user
        if msg['sender_username'] == CURRENT_USER:
            other_party = msg['recipient_username']
        elif msg['recipient_username'] == CURRENT_USER:
            other_party = msg['sender_username']
        else:
            continue
        conv_id = other_party

        # For uniqueness, use other_party username as conv_id
        if conv_id not in conversations_dict:
            conversations_dict[conv_id] = {
                'conversation_id': hash(conv_id) & 0xffffffff,  # simple int id
                'other_party_username': conv_id,
                'last_message_preview': '',
                'last_message_timestamp': ''
            }

        # Update last message if this msg is newer
        last_ts_str = conversations_dict[conv_id]['last_message_timestamp']
        if not last_ts_str or msg['timestamp'] > last_ts_str:
            preview_text = msg['content'][:50] + ('...' if len(msg['content']) > 50 else '')
            conversations_dict[conv_id]['last_message_preview'] = preview_text
            conversations_dict[conv_id]['last_message_timestamp'] = msg['timestamp']

    conversations = list(conversations_dict.values())
    conversations.sort(key=lambda x: x['last_message_timestamp'], reverse=True)
    return render_template('messages.html', conversations=conversations)

@app.route('/send_message', methods=['POST'])
def send_message():
    messages = read_messages()
    form = request.form
    recipient_username = form.get('recipient_username', '').strip()
    subject = form.get('subject', '').strip()
    content = form.get('content', '').strip()

    if not recipient_username or not subject or not content:
        # For simplicity redirect back
        return redirect(url_for('messages_page'))

    max_id = max((msg['message_id'] for msg in messages), default=0)
    new_id = max_id + 1

    now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    new_msg = {
        'message_id': new_id,
        'sender_username': CURRENT_USER,
        'recipient_username': recipient_username,
        'subject': subject,
        'content': content,
        'timestamp': now,
        'is_read': 'false'
    }
    messages.append(new_msg)
    write_messages(messages)

    return redirect(url_for('messages_page'))

