@app.route('/submit_pet', methods=['POST'])
def submit_pet():
    pets = read_pets()
    # Extract form data
    form = request.form

    pet_id_str = form.get('pet_id', '').strip()
    is_edit = False
    existing_pet_index = None
    if pet_id_str.isdigit():
        pet_id = int(pet_id_str)
        for i, pet in enumerate(pets):
            if pet['pet_id'] == pet_id:
                is_edit = True
                existing_pet_index = i
                break
    else:
        pet_id = None

    name = form.get('pet_name_input', '').strip()
    species = form.get('pet_species_input', '').strip()
    breed = form.get('pet_breed_input', '').strip()
    age = form.get('pet_age_input', '').strip()
    gender = form.get('pet_gender_input', '').strip()
    size = form.get('pet_size_input', '').strip()
    description = form.get('pet_description_input', '').strip()

    # Validation minimal: name and species required
    if not name or not species:
        # For simplicity redirect back to add_pet page
        return redirect(url_for('add_pet_page'))

    if is_edit:
        # Update existing pet
        pets[existing_pet_index]['name'] = name
        pets[existing_pet_index]['species'] = species
        pets[existing_pet_index]['breed'] = breed
        pets[existing_pet_index]['age'] = age
        pets[existing_pet_index]['gender'] = gender
        pets[existing_pet_index]['size'] = size
        pets[existing_pet_index]['description'] = description
        # Preserve shelter_id, status, date_added
    else:
        # Assign new pet ID
        max_id = max((pet['pet_id'] for pet in pets), default=0)
        new_pet_id = max_id + 1
        # For new pet, set shelter_id to 1, status to Available, date_added to today
        new_pet = {
            'pet_id': new_pet_id,
            'name': name,
            'species': species,
            'breed': breed,
            'age': age,
            'gender': gender,
            'size': size,
            'description': description,
            'shelter_id': 1,
            'status': 'Available',
            'date_added': datetime.today().strftime('%Y-%m-%d')
        }
        pets.append(new_pet)

    write_pets(pets)
    return redirect(url_for('pet_listings_page'))

