def read_users():
    users = []
    filepath = os.path.join(DATA_DIR, 'users.txt')
    if os.path.isfile(filepath):
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 4:
                    continue
                users.append({
                    'username': parts[0],
                    'email': parts[1],
                    'phone': parts[2],
                    'address': parts[3]
                })
    return users

