    filepath = os.path.join(DATA_DIR, 'users.txt')
    with open(filepath, 'w', encoding='utf-8') as f:
        for user in users:
            line = '|'.join([user.get('username', ''), user.get('email', ''), user.get('phone', ''), user.get('address', '')])
            f.write(line + '\n')


