    messages = read_messages()
    # Conversations keyed by other party username
    conversations_map = {}
    for msg in messages:
        if msg['sender_username'] == CURRENT_USER:
            other_user = msg['recipient_username']
        elif msg['recipient_username'] == CURRENT_USER:
            other_user = msg['sender_username']
        else:
            continue

        conv_id = other_user

        # Initialize conversation if not present
        if conv_id not in conversations_map:
            conversations_map[conv_id] = {
                'conversation_id': abs(hash(conv_id)) % (10 ** 8),
                'other_party_username': conv_id,
                'last_message_preview': '',
                'last_message_timestamp': ''
            }

        # Update last message preview and timestamp if recent
        current_last_ts = conversations_map[conv_id]['last_message_timestamp']
        if current_last_ts == '' or msg['timestamp'] > current_last_ts:
            preview = msg['content'][:50] + ('...' if len(msg['content']) > 50 else '')
            conversations_map[conv_id]['last_message_preview'] = preview
            conversations_map[conv_id]['last_message_timestamp'] = msg['timestamp']

    conversations = list(conversations_map.values())
    conversations.sort(key=lambda c: c['last_message_timestamp'], reverse=True)

    return render_template('messages.html', conversations=conversations)

