from flask import Flask, render_template, redirect, url_for, request, flash
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# ----------------------
# Utility functions for data handling
# ----------------------

def read_jobs():
    """Read jobs.txt and return a list of job dicts."""
    filepath = os.path.join(DATA_DIR, 'jobs.txt')
    jobs = []
    if not os.path.exists(filepath):
        return jobs
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 9:
                # corrupt or incomplete line, ignore
                continue
            try:
                job = {
                    'job_id': int(parts[0]),
                    'title': parts[1],
                    'company_id': int(parts[2]),
                    'location': parts[3],
                    'salary_min': int(parts[4]),
                    'salary_max': int(parts[5]),
                    'category': parts[6],
                    'description': parts[7],
                    'posted_date': parts[8]
                }
                jobs.append(job)
            except (ValueError, IndexError):
                # skip invalid entries
                continue
    return jobs


def save_jobs(jobs):
    """Save list of job dicts to jobs.txt in the correct format."""
    filepath = os.path.join(DATA_DIR, 'jobs.txt')
    lines = []
    for job in jobs:
        line = f"{job['job_id']}|{job['title']}|{job['company_id']}|{job['location']}|{job['salary_min']}|{job['salary_max']}|{job['category']}|{job['description']}|{job['posted_date']}"
        lines.append(line)
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))


def read_companies():
    filepath = os.path.join(DATA_DIR, 'companies.txt')
    companies = []
    if not os.path.exists(filepath):
        return companies
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 6:
                continue
            try:
                company = {
                    'company_id': int(parts[0]),
                    'company_name': parts[1],
                    'industry': parts[2],
                    'location': parts[3],
                    'employee_count': int(parts[4]),
                    'description': parts[5]
                }
