from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Data reading and writing functions for each data file

def read_jobs():
    path = os.path.join(DATA_DIR, 'jobs.txt')
    jobs = []
    if not os.path.isfile(path):
        return jobs
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 9:
                continue
            try:
                jobs.append({
                    'job_id': int(parts[0]),
                    'title': parts[1],
                    'company_id': int(parts[2]),
                    'location': parts[3],
                    'salary_min': int(parts[4]),
                    'salary_max': int(parts[5]),
                    'category': parts[6],
                    'description': parts[7],
                    'posted_date': parts[8]
                })
            except Exception:
                continue
    return jobs

def save_jobs(jobs):
    path = os.path.join(DATA_DIR, 'jobs.txt')
    with open(path, "w", encoding="utf-8") as f:
        for job in jobs:
            line = f"{job['job_id']}|{job['title']}|{job['company_id']}|{job['location']}|{job['salary_min']}|{job['salary_max']}|{job['category']}|{job['description']}|{job['posted_date']}"
            f.write(line + "\n")

def read_companies():
    path = os.path.join(DATA_DIR, 'companies.txt')
    companies = []
    if not os.path.isfile(path):
        return companies
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 6:
                continue
            try:
                companies.append({
                    'company_id': int(parts[0]),
                    'company_name': parts[1],
                    'industry': parts[2],
                    'location': parts[3],
                    'employee_count': int(parts[4]),
                    'description': parts[5]
                })
            except Exception:
                continue
    return companies

def save_companies(companies):
    path = os.path.join(DATA_DIR, 'companies.txt')
    with open(path, "w", encoding="utf-8") as f:
        for company in companies:
            line = f"{company['company_id']}|{company['company_name']}|{company['industry']}|{company['location']}|{company['employee_count']}|{company['description']}"
            f.write(line + "\n")

def read_categories():
    path = os.path.join(DATA_DIR, 'categories.txt')
    categories = []
    if not os.path.isfile(path):
        return categories
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 3:
                continue
            try:
                categories.append({
                    'category_id': int(parts[0]),
                    'category_name': parts[1],
