    resumes = read_resumes()
    resume_to_delete = None
    for r in resumes:
        if r['resume_id'] == resume_id:
            resume_to_delete = r
            break
    if resume_to_delete:
        # Delete file physically
        filename = resume_to_delete['filename']
        filepath = os.path.join(DATA_DIR, 'resumes', filename)
