@app.route('/dashboard')
def dashboard_page():
    jobs = read_jobs()
    # Sort descending by posted_date
    jobs_sorted = sorted(jobs, key=lambda j: j['posted_date'], reverse=True)
    featured_jobs = []
    count = 0
    for job in jobs_sorted:
