from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions for data loading and saving

def load_memberships():
    memberships = []
    try:
        with open(os.path.join(DATA_DIR, 'memberships.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                membership_id = int(parts[0])
                plan_name = parts[1]
                price = float(parts[2])
                billing_cycle = parts[3]
                features = parts[4]
                max_classes = parts[5]
                # max_classes can be int or string (e.g. "unlimited")
                try:
                    max_classes_val = int(max_classes)
                except ValueError:
                    max_classes_val = max_classes
                memberships.append({
                    'membership_id': membership_id,
                    'plan_name': plan_name,
                    'price': price,
                    'billing_cycle': billing_cycle,
                    'features': features,
                    'max_classes': max_classes_val
                })
    except Exception:
        # On error, return empty list
        memberships = []
    return memberships


def load_classes():
    classes = []
    try:
        with open(os.path.join(DATA_DIR, 'classes.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 8:
                    continue
                class_id = int(parts[0])
                class_name = parts[1]
                trainer_id = int(parts[2])
                class_type = parts[3]
                schedule_day = parts[4]
                schedule_time = parts[5]
                capacity = int(parts[6])
                duration = int(parts[7])
                classes.append({
                    'class_id': class_id,
                    'class_name': class_name,
                    'trainer_id': trainer_id,
                    'class_type': class_type,
                    'schedule_day': schedule_day,
                    'schedule_time': schedule_time,
                    'capacity': capacity,
                    'duration': duration
                })
    except Exception:
        classes = []
    return classes


def load_trainers():
    trainers = []
    try:
        with open(os.path.join(DATA_DIR, 'trainers.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                trainer_id = int(parts[0])
                name = parts[1]
                specialty = parts[2]
                certifications = parts[3]
                experience_years = int(parts[4])
                bio = parts[5]
                trainers.append({
                    'trainer_id': trainer_id,
                    'name': name,
                    'specialty': specialty,
                    'certifications': certifications,
                    'experience_years': experience_years,
                    'bio': bio
                })
    except Exception:
        trainers = []
    return trainers


def load_bookings():
    bookings = []
    try:
        with open(os.path.join(DATA_DIR, 'bookings.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 7:
                    continue
                booking_id = int(parts[0])
                member_name = parts[1]
                trainer_id = int(parts[2])
                booking_date = parts[3]
                booking_time = parts[4]
                duration_minutes = int(parts[5])
                status = parts[6]
                bookings.append({
                    'booking_id': booking_id,
                    'member_name': member_name,
                    'trainer_id': trainer_id,
                    'booking_date': booking_date,
                    'booking_time': booking_time,
                    'duration_minutes': duration_minutes,
                    'status': status
                })
    except Exception:
        bookings = []
    return bookings


def save_booking(booking_dict):
    # Append booking to bookings.txt with new booking_id
    try:
        bookings = load_bookings()
        if bookings:
            max_id = max(b['booking_id'] for b in bookings)
        else:
            max_id = 0
        new_id = max_id + 1
        line = f"{new_id}|{booking_dict['member_name']}|{booking_dict['trainer_id']}|{booking_dict['booking_date']}|{booking_dict['booking_time']}|{booking_dict['duration_minutes']}|{booking_dict['status']}\n"
        with open(os.path.join(DATA_DIR, 'bookings.txt'), 'a', encoding='utf-8') as f:
            f.write(line)
        return True
    except Exception:
        return False


def load_workouts():
