def load_alerts():
    alerts = []
    path = 'data/alerts.txt'
    if os.path.isfile(path):
        try:
            with open(path, 'r', encoding='utf-8') as f:
                for line in f:
                    parts = line.strip().split('|')
                    if len(parts) == 8:
                        alert = {
                            'alert_id': int(parts[0]),
                            'location_id': int(parts[1]),
                            'alert_type': parts[2],
                            'severity': parts[3],
                            'description': parts[4],
                            'start_time': parts[5],
                            'end_time': parts[6],
                            'is_acknowledged': parts[7] == '1',
                        }
                        alerts.append(alert)
        except Exception:
            pass
    return alerts


def load_air_quality():
    aqi_list = []
    path = 'data/air_quality.txt'
    if os.path.isfile(path):
        try:
            with open(path, 'r', encoding='utf-8') as f:
                for line in f:
                    parts = line.strip().split('|')
                    if len(parts) == 8:
                        aqi = {
                            'aqi_id': int(parts[0]),
