    activity_logs = []
    try:
        with open(ACTIVITY_LOGS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 5:
                    continue
                uname, timestamp, device_id, action, details = fields
                if uname != username:
                    continue
                activity_logs.append({
                    'username': uname,
                    'timestamp': timestamp,
                    'device_id': safe_int(device_id),
                    'action': action,
                    'details': details
                })
    except FileNotFoundError:
        pass
    return activity_logs

# Util: Get next available ID from a list of dicts keyed by id_key

def get_next_id(items, id_key):
    if not items:
        return 1
    max_id = max([item[id_key] or 0 for item in items])
    return max_id + 1

# Util: Find device by device_id

def find_device(devices, device_id):
    for d in devices:
        if d['device_id'] == device_id:
            return d
    return None

# --- Flask Routes ---

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    # Load devices and rooms for CURRENT_USERNAME
    devices = load_devices(CURRENT_USERNAME)
    rooms = load_rooms(CURRENT_USERNAME)
    # devices_summary: total devices, active devices (status Online), offline devices (status Offline)
    total_devices = len(devices)
    active_devices = sum(1 for d in devices if d['status'] == 'Online')
    offline_devices = total_devices - active_devices

    # Rooms list dicts must also contain device count per room
    room_list = []
    for room in rooms:
        room_name = room['room_name']
        count = sum(1 for d in devices if d['room'] == room_name)
        room_list.append({'room_name': room_name, 'device_count': count})

    devices_summary = {
        'total_devices': total_devices,
        'active_devices': active_devices,
        'offline_devices': offline_devices
    }
    return render_template('dashboard.html', devices_summary=devices_summary, rooms=room_list)

@app.route('/devices')
def device_list():
    devices = load_devices(CURRENT_USERNAME)
    return render_template('devices.html', devices=devices)

@app.route('/device/add', methods=['GET', 'POST'])
def add_device():
    if request.method == 'GET':
        # Provide rooms (list of strings) and device_types
        rooms_objs = load_rooms(CURRENT_USERNAME)
        rooms = [r['room_name'] for r in rooms_objs]
        # If no rooms found, fallback to default ROOM_NAMES
        if not rooms:
            rooms = ROOM_NAMES
        device_types = DEVICE_TYPES
        return render_template('add_device.html', rooms=rooms, device_types=device_types)
    else:
        # POST: Add a device
        # Expecting device_name(str), device_type(str), device_room(str) from form
        device_name = request.form.get('device_name', '').strip()
        device_type = request.form.get('device_type', '').strip()
        device_room = request.form.get('device_room', '').strip()

        if not device_name or not device_type or not device_room:
            # Missing required fields - simply reload form with same options
            rooms_objs = load_rooms(CURRENT_USERNAME)
            rooms = [r['room_name'] for r in rooms_objs]
            if not rooms:
                rooms = ROOM_NAMES
            device_types = DEVICE_TYPES
            return render_template('add_device.html', rooms=rooms, device_types=device_types)

        # load current devices to determine next device_id
        devices = load_devices(CURRENT_USERNAME)
        next_device_id = get_next_id(devices, 'device_id')

        # Add device with default brand, model, status=Offline, power=off, empty brightness, temperature, mode, schedule_time
        new_device = {
            'username': CURRENT_USERNAME,
            'device_id': next_device_id,
            'device_name': device_name,
            'device_type': device_type,
            'room': device_room,
            'brand': '',
            'model': '',
            'status': 'Offline',
            'power': 'off',
            'brightness': None,
            'temperature': None,
            'mode': None,
            'schedule_time': None
        }
        devices.append(new_device)
        save_devices(CURRENT_USERNAME, devices)

        return redirect(url_for('device_list'))

@app.route('/device/<int:device_id>', methods=['GET', 'POST'])
def device_control(device_id):
    devices = load_devices(CURRENT_USERNAME)
    device = find_device(devices, device_id)
    if device is None:
        # 404 Not Found
        return "Device not found", 404

    if request.method == 'GET':
        return render_template('device_control.html', device=device)
    else:
        # POST - save device settings
        # Form fields expected: power (on/off), brightness (int or empty), temperature (int or empty), mode (str or empty), schedule_time (str or empty)
        power = request.form.get('power', device['power']).strip().lower()
        brightness_raw = request.form.get('brightness','').strip()
        temperature_raw = request.form.get('temperature','').strip()
        mode = request.form.get('mode', '').strip() or None
        schedule_time = request.form.get('schedule_time', '').strip() or None

        brightness = safe_int(brightness_raw) if brightness_raw else None
        temperature = safe_int(temperature_raw) if temperature_raw else None

        # Update device fields
        device['power'] = 'on' if power == 'on' else 'off'
        device['brightness'] = brightness
        device['temperature'] = temperature
        device['mode'] = mode
        device['schedule_time'] = schedule_time

        # Mark status Online if power on else Offline
        device['status'] = 'Online' if device['power'] == 'on' else 'Offline'

        # Save devices back
        save_devices(CURRENT_USERNAME, devices)

        return redirect(url_for('device_control', device_id=device_id))

@app.route('/automation', methods=['GET', 'POST'])
def automation_rules():
    if request.method == 'GET':
        rules = load_automation_rules(CURRENT_USERNAME)
        devices = load_devices(CURRENT_USERNAME)
        return render_template('automation.html', automation_rules=rules, devices=devices)
    else:
        # POST: Add a new automation rule
        rule_name = request.form.get('rule_name', '').strip()
        trigger_type = request.form.get('trigger_type', '').strip()
        trigger_value = request.form.get('trigger_value', '').strip()
        action_device_id_str = request.form.get('action_device', '').strip()
        action_type = request.form.get('action_type', '').strip()

        if not rule_name or not trigger_type or not action_device_id_str or not action_type:
            # Invalid data, redirect to GET
            return redirect(url_for('automation_rules'))

        try:
            action_device_id = int(action_device_id_str)
        except ValueError:
            return redirect(url_for('automation_rules'))

        rules = load_automation_rules(CURRENT_USERNAME)
        next_rule_id = get_next_id(rules, 'rule_id')

        new_rule = {
            'username': CURRENT_USERNAME,
            'rule_id': next_rule_id,
            'rule_name': rule_name,
            'trigger_type': trigger_type,
            'trigger_value': trigger_value,
            'action_device_id': action_device_id,
            'action_type': action_type,
            'action_value': None,
            'enabled': True
        }
        rules.append(new_rule)
        save_automation_rules(CURRENT_USERNAME, rules)

        return redirect(url_for('automation_rules'))

@app.route('/energy', methods=['GET', 'POST'])
def energy_report():
    filter_date = None
    if request.method == 'POST':
        filter_date = request.form.get('date_filter', '').strip()
        if filter_date == '':
            filter_date = None
    energy_data_all = load_energy_logs(CURRENT_USERNAME)
    # Filter data by date if filter_date provided
    if filter_date:
        energy_data = [e for e in energy_data_all if e['date'] == filter_date]
    else:
        energy_data = energy_data_all

    # Aggregate summary totals
    total_consumption = sum(e['consumption_kwh'] for e in energy_data if e['consumption_kwh'] is not None)
    # Assume cost estimate is total_consumption * 0.12 (USD per kWh)
    energy_summary = {
        'total_consumption': total_consumption,
        'cost_estimate': round(total_consumption * 0.12, 2)
    }

    return render_template('energy.html', energy_data=energy_data, energy_summary=energy_summary, filter_date=filter_date)

@app.route('/activity', methods=['GET', 'POST'])
def activity_logs():
    search_query = None
    activity_logs_all = load_activity_logs(CURRENT_USERNAME)
    if request.method == 'POST':
        search_query = request.form.get('search_query', '').strip().lower()
        if search_query:
            filtered_logs = []
            for log in activity_logs_all:
                # Search in timestamp, device_id as str, action, details
                if (search_query in log['timestamp'].lower() or
